import{_ as l,o as t,c as r,a2 as a}from"./chunks/framework.4hJCcvDE.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_001-C++11.md","filePath":"blog/知识点_001-C++11.md","lastUpdated":1784835052000}'),i={name:"blog/知识点_001-C++11.md"};function o(p,e,s,n,c,_){return t(),r("div",null,[...e[0]||(e[0]=[a('<ol><li>之前比较难理解的主要就是右值和左值，右值引用和左值引用。</li></ol><ul><li>左值与右值的根本区别在于是否允许取址运算符（&amp;）获得对应的内存地址。左值和右值比较简单的理解，也就是顾名思义，在赋值表达式中，用在=号左侧的是左值，是可以被赋值的，多半是一个声明过的变量，但是用在等号右侧的不一定就是右值，因为左值也可以出现在=号右侧，通常来讲我们说的右值一般是函数返回值(使用运算符的表达式返回结果同理)，它是一个临时对象，或者是一个字面量比如10，“bob”这种。接下来是左值引用和右值引用，左值引用没什么好说的，一般就是变量的引用这个平时用的很多。而右值引用这个是c++11新加的东西，这个就值得研究一下了。</li></ul><ol start="2"><li>右值引用主要意义在于实现移动语义和完美转发。</li></ol><ul><li><p>std::move可以把左值引用转为右值引用，这个东西主要作用在于避免一些临时对象的多余复制。比如当临时对象有移动构造函数时，在使用stl容器的时候就可以在pushback的时候使用std::move省去一次拷贝构造和析构。</p></li><li><p>std::forward这个的主要作用在于他不会把右值转换为左值，避免了内存分配。</p></li><li><p>从性能上讲，左右值引用没有区别，传参使用左右值引用都可以避免拷贝。</p></li><li><p>右值引用可以直接指向右值，也可以通过std::move指向左值；而左值引用只能指向左值(const左值引用也能指向右值)。</p></li><li><p>作为函数形参时(int &amp;&amp;ref为右值引用, int &amp;ref为左值引用)，右值引用更灵活。虽然const左值引用也可以做到左右值都接受，但它无法修改，有一定局限性。</p></li></ul><ol start="3"><li>tips:</li></ol><ul><li><p>左值引用不能指向右值，但是const左值引用可以。比如 const int &amp;ref_a = 5; 是可以编译通过的，因为const左值引用无法修改指向的值，所以可以指向右值。c++标准库中的vector push_back void push_back (const value_type&amp; val); 就是这样实现的，如果没有这个const, vector.push_back(1)，这种代码是无法编译通过的。</p></li><li><p>编译器会默认在用户自定义的class和struct中生成移动语义函数，但前提是用户没有主动定义该类的拷贝构造等函数</p></li></ul><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><p><a href="https://www.ibm.com/developerworks/cn/aix/library/1307_lisl_c11/index.html" target="_blank" rel="noreferrer">右值引用与转移语义</a></p></li><li><p><a href="https://zh.m.wikipedia.org/zh-hans/%E5%8F%B3%E5%80%BC%E5%BC%95%E7%94%A8" target="_blank" rel="noreferrer">右值引用</a></p></li><li><p><a href="https://www.zhihu.com/question/22111546" target="_blank" rel="noreferrer">如何评价 C++11 的右值引用（Rvalue reference）特性？--知乎</a></p></li><li><p><a href="https://zh.wikipedia.org/wiki/C%2B%2B11#%E5%9F%B7%E8%A1%8C%E7%B7%92%E6%94%AF%E6%8F%B4" target="_blank" rel="noreferrer">C++11--维基百科</a></p></li><li><p><a href="https://zh.cppreference.com/w/cpp/utility/functional/function" target="_blank" rel="noreferrer">C++ 参考手册--cppreference</a></p></li></ul><blockquote><p>未完待续</p></blockquote>',9)])])}const f=l(i,[["render",o]]);export{u as __pageData,f as default};
